-- ============================================================================
-- GCU Prospect Pipeline — Supabase schema
-- Run this once in the Supabase SQL Editor (Project > SQL Editor > New query)
-- for a fresh project. Safe to run top-to-bottom, and safe to re-run.
-- ============================================================================

-- 1. PROSPECTS ---------------------------------------------------------------
create table if not exists prospects (
  id               bigint primary key,
  list             text not null default 'SOHK',  -- 'SOHK' | 'KIC' — which tool tab this prospect belongs to
  tier             text,                          -- 'Whale' | 'Review' | 'Contact' | null
  name             text not null,
  role             text,
  org              text,
  category         text,
  location          text,
  email            text,
  email2           text,
  priority         text,                          -- 'high' | 'medium' | 'low'
  faith_confirmed  boolean not null default false,
  score            int,
  stage            text,                          -- 'Emailed' | 'Interested' | 'Met with' | 'Confirmed' | null
  bio              text,
  approach         text,
  faith            text,
  angle            text,
  tags             jsonb not null default '[]'::jsonb,
  news             jsonb not null default '[]'::jsonb,
  notable          text,                          -- short "what makes them notable" line (KIC data)
  draft_email      text,                          -- pre-written outreach email draft, if one exists
  source_urls      jsonb not null default '[]'::jsonb,  -- verified source links, shown in "Verified Sources" panel
  created_at       timestamptz not null default now(),
  updated_at       timestamptz not null default now()
);

-- Safe to re-run: adds these columns if this table already existed from
-- before the SOHK/KIC combination (June 2026).
alter table prospects add column if not exists list text not null default 'SOHK';
alter table prospects add column if not exists notable text;
alter table prospects add column if not exists draft_email text;
alter table prospects add column if not exists source_urls jsonb not null default '[]'::jsonb;
create index if not exists idx_prospects_list on prospects(list);

comment on column prospects.stage is 'Engagement stage filter: Emailed, Interested, Met with, Confirmed. Null = not yet engaged.';
comment on column prospects.list is 'Which tab this prospect belongs to: SOHK (School of Hard Knocks) or KIC (Kingdom Impact Council).';

-- 2. TOUCHPOINTS --------------------------------------------------------------
-- One row per follow-up / contact event logged against a prospect.
create table if not exists touchpoints (
  id            bigserial primary key,
  prospect_id   bigint not null references prospects(id) on delete cascade,
  type          text not null,                    -- 'Email' | 'Call' | 'Meeting' | 'Text' | 'Other'
  note          text,
  logged_by     text,                              -- free-text name of whoever logged it
  touch_date    date not null default current_date,
  created_at    timestamptz not null default now()
);

create index if not exists idx_touchpoints_prospect on touchpoints(prospect_id);
create index if not exists idx_touchpoints_date on touchpoints(touch_date desc);

-- 3. updated_at auto-touch trigger --------------------------------------------
create or replace function set_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

drop trigger if exists trg_prospects_updated_at on prospects;
create trigger trg_prospects_updated_at
  before update on prospects
  for each row execute function set_updated_at();

-- 4. Row Level Security --------------------------------------------------------
-- This is an internal team tool gated by a shared anon key (not public signup),
-- so we allow full read/write to anyone holding the anon key.
alter table prospects enable row level security;
alter table touchpoints enable row level security;

drop policy if exists "prospects_all_access" on prospects;
create policy "prospects_all_access" on prospects for all using (true) with check (true);

drop policy if exists "touchpoints_all_access" on touchpoints;
create policy "touchpoints_all_access" on touchpoints for all using (true) with check (true);

-- 5. Realtime ------------------------------------------------------------------
-- Lets every connected browser see edits from teammates without refreshing.
alter publication supabase_realtime add table prospects;
alter publication supabase_realtime add table touchpoints;

-- ============================================================================
-- 6. Seed data: your existing 82 researched SOHK prospects
-- ============================================================================
insert into prospects (id, list, tier, name, role, org, category, location, email, email2, priority, faith_confirmed, score, stage, bio, approach, faith, angle, tags, news, notable, draft_email, source_urls) values
(1, 'SOHK', 'Review', 'James Dumoulin', 'Co-Founder', 'School of Hard Knocks', 'Media', 'Austin, TX', 'james@shophardknocks.com', NULL, 'high', true, 88, NULL, 'James Dumoulin is the 23-year-old co-founder of School of Hard Knocks, a media platform generating over $1M/month in revenue with 22M+ followers and over 4 billion views. He built an 8-figure business by walking up to strangers — billionaires, celebrities, athletes — and asking them how they made their money. He''s interviewed Will Smith, Mark Cuban, Gary Vaynerchuk, Tom Cruise, and Todd Graves. His speaking fee runs $30,000–$50,000. He''s been featured on the Faith Driven Entrepreneur podcast and multiple entrepreneurship shows.', 'Cold approach works — James literally built his brand on cold approaches. DM him directly on Instagram or LinkedIn referencing GCU''s entrepreneurial mission and Canyon Ventures. He interviewed Todd Graves (also on this list) — that''s a warm chain. A campus visit to interview GCU entrepreneurs for his channel is a natural ask that benefits both sides.', 'Featured on Faith Driven Entrepreneur podcast. His School of Hard Knocks content has appeared alongside openly Christian entrepreneurs including Myron Golden and Todd Graves. Values-driven content focused on discipline and real-world wisdom.', 'GCU''s Canyon Ventures and entrepreneur-focused curriculum is exactly what James''s platform champions. His audience is precisely GCU''s demographic. A campus shoot, Canyon Ventures partnership, or student speaker event would be mutually beneficial.', '["Gen Z", "8-Figure Business", "22M Followers", "Social Media", "School of Hard Knocks"]'::jsonb, '[{"date": "Apr 2026", "title": "Episode: What @SchoolofHardKnocks Creator Has Learned Interviewing Billionaires", "source": "Faith Driven Entrepreneur Podcast"}, {"date": "Apr 2026", "title": "Episode 547: The Kid Who Built an 8-Figure Business By Asking Billionaires How Much They Make", "source": "Apple Podcasts"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(2, 'SOHK', 'Review', 'Myron Golden', 'Founder & CEO', 'Skillionaire Enterprises / Bible Success Academy', 'Entrepreneur', 'Tampa, FL', 'myron@myrongoldenconsulting.com', NULL, 'high', true, 92, NULL, 'Myron Golden is an entrepreneur, bestselling author, business coach, and speaker with an estimated net worth of $25M. He overcame childhood polio and poverty to build an empire teaching Biblical principles of wealth creation. He holds a degree in Accounting from Howard University and an advanced degree from Harvard. He''s the author of ''From the Trash Man to the Cash Man'' and ''BOSS Moves,'' and is the founder of Bible Success Academy. He charges ~$250,000 per speech and $25,000/hour for consulting and generates $2–3M/month.', 'Reach out through his Skillionaire Enterprises team or his speaking bureau. Lead with GCU''s faith-based entrepreneurship mission and the fact that GCU''s model (affordable tuition, Christian values, real-world focus) is the kind of institution he''d want his community to know about. A keynote at Canyon Ventures or a GCU business school speaker series is the natural ask.', 'Deeply and openly Christian. Integrates Biblical principles into every business teaching. Founder of Bible Success Academy. Member of Cornerstone Baptist Church. Speaks extensively at Christian entrepreneur events. Frequently quotes scripture in business context.', 'Myron''s entire brand is faith-driven entrepreneurship — GCU''s Entrepreneurial Science program is a direct institutional match. Speaker series, guest lecture, advisory role, or scholarship fund alignment are all natural asks.', '["Biblical Business", "$25M Net Worth", "Author", "Speaking Circuit", "Faith Leader"]'::jsonb, '[{"date": "2026", "title": "Make More Offers Challenge \u2014 helping thousands of entrepreneurs scale with Biblical principles", "source": "Skillionaire Enterprises"}, {"date": "2025", "title": "BOSS Moves \u2014 bestselling business framework continues growing", "source": "Amazon"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(3, 'SOHK', 'Review', 'Todd Graves', 'Founder, CEO, Fry Cook & Cashier', 'Raising Cane''s Chicken Fingers', 'Entrepreneur', 'Baton Rouge, LA', 'info@raisingcanes.com', NULL, 'high', true, 95, NULL, 'Todd Graves is the co-founder of Raising Cane''s Chicken Fingers, with a net worth of $22 billion as of 2026 — ranked #46 on the Forbes 400. He built the company from a B- business school grade and bank rejections, working as a boilermaker and Alaskan salmon fisherman to fund his dream. He opened the first location near LSU in 1996 and grew it to 900+ locations and $5.1B in annual revenue. He is one of the most iconic founder stories in American business.', 'Todd is warm toward faith-based institutions and community causes. Approach through Raising Cane''s corporate philanthropy team or through a warm intro via James Dumoulin (who has already interviewed Todd on his channel). Lead with GCU''s workforce development and the fact that Raising Cane''s offers $5,250/yr in tuition reimbursement — shared mission on education.', 'Devout Christian. Publicly stated: ''I believe God made me good at chicken fingers to help people. I think God makes us all good at what we''re doing, ultimately, to help people.'' Partnered with The Advocate''s Faith in the Community directory during COVID. His faith is woven into his business philosophy and public identity.', 'Todd''s story — professor said no, banks said no, he built anyway — is the GCU narrative. His $5,250/yr tuition benefit shows he invests in employee education. Workforce pipeline, speaker series, and philanthropy around GCU''s workforce programs are the strongest angles.', '["$22B Net Worth", "Forbes 400 #46", "Faith Leader", "Workforce Education", "Raising Cane''s"]'::jsonb, '[{"date": "Jan 2026", "title": "Forbes: Todd Graves ranked #46 on Forbes 400, net worth $22 billion", "source": "Forbes"}, {"date": "2025", "title": "Raising Cane''s surpasses 900 locations, $5.1B annual revenue", "source": "QSR Magazine"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(4, 'SOHK', 'Whale', 'Mark Cuban', 'Entrepreneur, Investor & Philanthropist', 'Shark Tank / Cost Plus Drugs / Dallas Mavericks', 'Entrepreneur', 'Dallas, TX', NULL, NULL, 'high', false, 78, NULL, 'Mark Cuban is a serial entrepreneur with an estimated net worth of $5.7 billion. He sold Broadcast.com to Yahoo! for $5.9 billion in 1999, owned the Dallas Mavericks (NBA champions 2011), and has been a Shark Tank investor for 15+ seasons. He co-founded Cost Plus Drugs to disrupt pharmaceutical pricing. The Mark Cuban Foundation runs AI Bootcamp programs for underserved youth and funds NFTE entrepreneurship education. He has been one of the most vocal critics of overpriced higher education.', 'Cuban has an open public profile and is known for responding to direct, substantive LinkedIn and Twitter messages. Lead with GCU''s $8,900/yr tuition stat — he is on record saying affordable universities are the future of higher ed. Connect through his foundation''s AI education work and GCU''s tech programs.', 'Jewish background. Not publicly faith-identified but deeply committed to education access and equity. Foundation focuses on AI literacy for underserved communities.', 'Cuban''s public critique of expensive higher ed + GCU''s $8,900/yr model = perfect alignment. He has also been interviewed by James Dumoulin — that''s a connection chain. His AI Bootcamp work connects to GCU''s tech and entrepreneurship curriculum.', '["$5.7B Net Worth", "Shark Tank", "Ed Reform", "AI Education", "Mark Cuban Foundation"]'::jsonb, '[{"date": "2025", "title": "Cost Plus Drugs continues disrupting pharmaceutical pricing market", "source": "Forbes"}, {"date": "2024", "title": "Mark Cuban Foundation AI Bootcamp expands to 50+ cities", "source": "Mark Cuban Foundation"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(5, 'SOHK', 'Review', 'Craig Jackson', 'Chairman & CEO', 'Barrett-Jackson Auction Company', 'Automotive', 'Scottsdale, AZ', 'cjackson@barrett-jackson.com', NULL, 'high', false, 82, NULL, 'Craig Jackson is the Chairman and CEO of Barrett-Jackson, the world''s premier collector car auction company, headquartered in Scottsdale, Arizona. His estimated net worth is $300M. Barrett-Jackson has raised over $118 million for charity through auctions, including $9.6M at the 2019 Scottsdale event alone. He took over at 35 after losing both his father and brother, grew the company into a national media and entertainment brand, and pioneered collector car auctions on television.', 'Craig is an active Arizona community leader. Approach through Barrett-Jackson''s Scottsdale headquarters directly, or through a local Arizona business network. GCU''s Phoenix presence and CityServe community mission are natural entry points. A Barrett-Jackson auction charity beneficiary relationship is a strong long-term play.', 'Deeply philanthropic. Supports American Cancer Society, National Guard Educational Foundation, Ronald McDonald House. Personal donation of $1.1M at 2019 Scottsdale auction alone. Service-driven leadership philosophy.', 'Arizona local — Barrett-Jackson HQ is in Scottsdale. His philanthropy model (auctions raising millions for local causes) aligns with CityServe''s community impact mission. GCU''s automotive/trades programs and workforce pipeline are relevant conversation starters.', '["Arizona Local", "$300M Net Worth", "Philanthropy", "Scottsdale", "Automotive"]'::jsonb, '[{"date": "Jan 2026", "title": "Barrett-Jackson Scottsdale 2026 sets new records for charity vehicle auctions", "source": "Barrett-Jackson"}, {"date": "2025", "title": "Barrett-Jackson celebrates 54 years as premier collector car auction", "source": "Barrett-Jackson"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(6, 'SOHK', 'Contact', 'Ben Pogue', 'Chairman (Former CEO)', 'Pogue Construction', 'Construction', 'McKinney, TX', NULL, NULL, 'high', true, 90, NULL, 'Ben Pogue took over Pogue Construction from his father at age 29 and grew it from $300M to $1.5B in annual revenue by 2025. In late 2025, he made the company employee-owned through an ESOP, saying ''This is more than a change in structure — it is our way of saying thank you.'' He then transitioned to Chairman while naming Lou Morelli CEO. He navigated a major public crisis (Allen Eagle Stadium) and came out stronger. Pogue ranks in the top 10 contractors in North Texas by the Dallas Business Journal.', 'Reach out through Pogue Construction''s McKinney headquarters. Lead with GCU''s Construction Management program — specific, relevant, and demonstrates you''ve done your homework. The ESOP transition shows he''s values-driven; lead with alignment, not just the ask. School of Hard Knocks podcast (James Dumoulin) interviewed Ben in early 2026 — that''s a warm chain.', 'Openly Christian. In public interviews he describes how ''culture, faith, and people-first leadership'' transformed his company. Strong servant-leader identity. ESOP decision was explicitly framed as a values act.', 'GCU''s Construction Management program is a direct match — advisory board, student mentorship pipeline, or guest speaker. His people-first leadership philosophy and GCU''s mission around workforce development are deeply aligned.', '["$1.5B Revenue", "Construction", "Faith Leader", "ESOP", "People-First"]'::jsonb, '[{"date": "Mar 2026", "title": "Pogue Construction names new CEO as Ben Pogue transitions to Chairman", "source": "Community Impact"}, {"date": "Dec 2025", "title": "McKinney-based Pogue Construction becomes employee-owned", "source": "Community Impact"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(7, 'SOHK', 'Review', 'Chris Herschend', 'Board Chair & Vice Chairman', 'Herschend Family Entertainment', 'Entertainment', 'Atlanta, GA', NULL, NULL, 'high', true, 91, NULL, 'Chris Herschend is a third-generation owner and board chair of Herschend Family Entertainment — the world''s largest family-owned themed attractions company with properties including Dollywood, Silver Dollar City, the Harlem Globetrotters, and 26 locations entertaining 15M+ guests annually. He earned his BA from Emory University and MBA from Emory''s Goizueta Business School. Earlier in his career he worked at The Coca-Cola Company and in private equity. He co-founded Elmwood Management, a private investment firm.', 'Connect through Faith Driven Entrepreneur network where Chris is an active participant. He frequently speaks at business schools and faith-leadership conferences — GCU''s business school is a natural venue. A speaker series invitation paired with a development ask around GCU''s faith-based business curriculum is the strongest approach.', 'Deeply and openly Christian. Herschend Family Entertainment was built on faith-driven values for 75+ years. Chris has spoken extensively at Faith Driven Entrepreneur events about stewardship and family legacy. Attends Passion City Church. Partner of Samaritan''s Purse. His father and uncle both came to Christian faith through their employees.', 'One of the most powerful examples of faith-driven multi-generational business leadership in America. GCU''s faith-based business programs, family values curriculum, and stewardship focus are a direct match. Speaker series, advisory role, or named scholarship in the entertainment/hospitality space.', '["Dollywood", "Silver Dollar City", "Faith-Driven Business", "Family Legacy", "Emory MBA"]'::jsonb, '[{"date": "Feb 2026", "title": "Chris Herschend speaks to Brookwood School FIE Club on stewardship and family legacy", "source": "Thomasville Times-Enterprise"}, {"date": "2025", "title": "Herschend Family Entertainment celebrates 75 years as faith-based family attractions leader", "source": "Herschend"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(8, 'SOHK', 'Review', 'Simon Squibb', 'Founder', 'HelpBnk', 'Entrepreneur', 'London, UK', 'commercial@simonsquibb.com', NULL, 'high', true, 86, NULL, 'Simon Squibb started his first business while homeless at 15. He founded and sold 19 companies including Fluid, which he sold to PwC. He now runs HelpBnk — a movement to help 10 million people start businesses for free. He has 22M+ followers across social platforms and generates 200M views per month organically. He is a No. 1 Sunday Times bestselling author. He famously installed a doorbell on a London staircase where entrepreneurs can walk up and pitch their dreams for funding.', 'Simon is very accessible on social media — his entire brand is built on open, public engagement. DM him on LinkedIn or Instagram with a specific proposition: GCU as a case study for the affordable, entrepreneurial, faith-aligned higher education model he''s been publicly campaigning for. Offer him a GCU campus visit or a collaboration on content about fixing higher education.', 'Openly Christian. Has publicly discussed his faith in interviews. Strongly advocates for fixing the education system — has spoken to UK government ministers and campaigned against education legislation that restricts alternative learning. Believes schools were designed to create obedient factory workers, not entrepreneurs.', 'Simon literally wants to fix higher education — GCU''s affordable, faith-based, entrepreneur-focused model is the institution he''s been describing. His 22M followers are aspiring entrepreneurs = GCU''s core demographic. Partnership, content collaboration, or GCU as a featured case study in his education reform mission.', '["22M Followers", "Higher Ed Reform", "Christian", "HelpBnk", "Sunday Times Bestseller"]'::jsonb, '[{"date": "May 2025", "title": "Simon Squibb slams UK Children''s Wellbeing and Schools Bill as threat to education freedom", "source": "EdTech Innovation Hub"}, {"date": "2024", "title": "HelpBnk reaches milestone in mission to help 10M people start businesses for free", "source": "HelpBnk"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(9, 'SOHK', 'Whale', 'Jameis Winston', 'NFL Quarterback', 'New York Giants', 'Sports', 'New York, NY', NULL, NULL, 'high', true, 84, NULL, 'Jameis Winston is a NFL quarterback currently with the New York Giants. He was the #1 overall pick in the 2015 NFL Draft by the Tampa Bay Buccaneers. He won the Heisman Trophy and BCS National Championship at Florida State. Career stats: 24,792 passing yards, 156 touchdowns across stints with the Buccaneers, Saints, Browns, and Giants. He led the NFL in passing yards in 2019 with 5,109 yards.', 'Reach out through his foundation or agent. Lead with GCU''s Christian identity and student athlete community. A chapel speaker event, motivational talk to GCU student-athletes, or joint community outreach initiative (given his prison ministry work with God Behind Bars) is the strongest ask.', 'One of the most openly Christian athletes in the NFL. Accepted Christ at age 8, rededicated at 19, baptized at 22 at a spiritual retreat for professional athletes. His X/Twitter bio reads: ''1. God 2. School (Learning Everyday) 3. Dream Forever'' with the hashtag #Phil413. Pregame interviews: ''Unwavering faith. Ultimate belief. Dependence on the Lord.'' Has spoken at Super Bowl Media Day about his faith. Partners with God Behind Bars prison ministry.', 'GCU''s sports programs and strong Christian identity are a natural fit. His ''2. School (Learning Everyday)'' is a direct GCU talking point. A chapel event, student-athlete mentorship program, or scholarship announcement would resonate widely.', '["NFL QB", "Heisman Trophy", "#1 Draft Pick", "Strong Christian", "God Behind Bars"]'::jsonb, '[{"date": "2025-26", "title": "Jameis Winston signs with New York Giants", "source": "NFL"}, {"date": "Nov 2024", "title": "Winston leads Cleveland Browns to upset win over Pittsburgh Steelers, credits ''Unwavering faith''", "source": "Christian Post"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(10, 'SOHK', 'Contact', 'John Lee Hoich', 'Founder', 'Hoich Enterprises', 'Real Estate', 'Phoenix, AZ', 'jhoich@hoich.com', NULL, 'high', true, 79, NULL, 'Arizona-based real estate entrepreneur and investor based in Phoenix. Local community presence and active in the Arizona faith-driven business community. Direct email available for warm outreach.', 'Direct email available: jhoich@hoich.com. Lead with GCU''s presence in the Phoenix metro, the growing campus footprint, and the CM/Real Estate program relevance. Faith is the connector — open with the shared mission angle.', 'Christian. Known as a faith-driven business leader in the Arizona entrepreneurial community.', 'Arizona local and Christian — GCU is in his backyard. Real estate background is directly relevant to GCU''s growing campus development, CM program, and potential real estate advisory relationships.', '["Arizona", "Phoenix", "Real Estate", "Christian", "Local Leader"]'::jsonb, '[]'::jsonb, NULL, NULL, '[]'::jsonb),
(11, 'SOHK', 'Whale', 'Giannis Antetokounmpo', 'NBA Superstar', 'Milwaukee Bucks', 'Sports', 'Milwaukee, WI', NULL, NULL, 'medium', true, 72, NULL, 'Giannis Antetokounmpo — ''The Greek Freak'' — is a 2x NBA MVP and 2021 NBA Champion with the Milwaukee Bucks. Born to Nigerian parents in Athens, Greece, he grew up in poverty, sometimes selling items on the street to survive. His family were undocumented immigrants. He rose from those conditions to become one of the greatest players in NBA history. His Antetokounmpo Family Charitable Foundation focuses on underprivileged youth and education.', 'Reach through the Antetokounmpo Family Foundation or through Bucks community relations. Lead with GCU''s CityServe and community development work — specifically the underprivileged youth angle which matches his foundation''s mission exactly. A joint community event in Phoenix during an away game is a natural connection point.', 'Devout Greek Orthodox Christian. Baptized at age 18 in Athens. Publicly quotes ''Walk by faith, not by sight.'' Thanked God upon winning the 2019 MVP award. His foundation explicitly lists ''Faith'' as a core value. Attends church when schedule permits and participates in significant faith events.', 'Giannis''s story — poverty, immigrant family, faith, determination — mirrors the students GCU serves. His foundation''s focus on underprivileged youth directly mirrors CityServe. A GCU partnership, joint community event, or scholarship announcement would be high-profile.', '["2x NBA MVP", "2021 Champion", "Greek Orthodox", "Underprivileged Youth", "Foundation"]'::jsonb, '[{"date": "2025-26", "title": "Giannis Antetokounmpo continues leadership of Milwaukee Bucks", "source": "NBA"}, {"date": "2020", "title": "Antetokounmpo Family Charitable Foundation launched to support underprivileged youth", "source": "Foundation"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(12, 'SOHK', 'Review', 'Marc Lore', 'Founder, Chairman & CEO', 'Wonder Group / Minnesota Timberwolves', 'Entrepreneur', 'New York, NY', NULL, NULL, 'medium', false, 68, NULL, 'Marc Lore is a serial entrepreneur and NBA co-owner. He sold Quidsi (Diapers.com) to Amazon for $545M and Jet.com to Walmart for $3.3B. He served as President and CEO of Walmart U.S. eCommerce from 2016–2021. He now runs Wonder Group, a food delivery super-app valued at $7B+, and co-owns the Minnesota Timberwolves and Lynx with Alex Rodriguez. He is also the lead investor in Archer (eVTOL aircraft) and Wizard (AI eCommerce).', 'Approach through Wonder Group or his public social media. Lead with GCU''s entrepreneurial talent pipeline — Wonder is actively hiring and scaling. His Walmart background creates a workforce development conversation entry point.', 'Purpose and family driven. Has publicly reflected on sacrificing personal life to build businesses and now seeks more meaning-driven work. Not publicly faith-identified.', 'GCU''s entrepreneurial ecosystem and tech programs are a talent pipeline he actively needs. NBA ownership opens a sports-angle conversation for student engagement. His Walmart/Amazon background aligns with workforce development programs.', '["$3.3B Jet.com Exit", "NBA Owner", "Wonder Group", "eCommerce", "Serial Entrepreneur"]'::jsonb, '[{"date": "Mar 2025", "title": "Inside the restless mind of a serial founder: Marc Lore on Wonder''s path to IPO", "source": "Fortune"}, {"date": "2025", "title": "Wonder Group tops $7B valuation in new funding round", "source": "TechCrunch"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(13, 'SOHK', 'Review', 'Stephen Cloobeck', 'Founder & Former CEO', 'Diamond Resorts International', 'Hospitality', 'Los Angeles, CA', NULL, NULL, 'medium', false, 65, NULL, 'Stephen Cloobeck is the founder of Diamond Resorts International, which he built into a global hospitality empire sold to Apollo Global Management for $2.2 billion in 2016. He served as inaugural chairman of Brand USA. He is a graduate of Brandeis University, author of ''Checking In: Hospitality-Driven Thinking, Business, and You,'' and has donated $1M to Brandeis for neuroscience research. He briefly ran for California governor in 2025-26.', 'Reach through his public office or through charitable organizations he supports. Lead with GCU''s hospitality program and the service-first philosophy he champions. His Brandeis donation shows willingness to support university programs he believes in.', 'Supports LA Dream Center (Christian), Keep Memory Alive, Brent Shapiro Foundation, and multiple educational initiatives. Service-driven leadership. Democratic background.', 'GCU''s hospitality program and his expertise in hospitality leadership are a natural match. His $1M Brandeis gift is a reference point for what a named program gift could look like.', '["$2.2B Exit", "Hospitality", "Philanthropy", "Brand USA", "Education Donor"]'::jsonb, '[{"date": "2025", "title": "Stephen Cloobeck ends California governor campaign", "source": "Business Wire"}, {"date": "2024", "title": "Cloobeck announces candidacy for Governor of California 2026", "source": "Business Wire"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(14, 'SOHK', 'Whale', 'John Morgan', 'Founder', 'Morgan & Morgan', 'Law', 'Orlando, FL', NULL, NULL, 'medium', false, 62, NULL, 'John Morgan is the founder of Morgan & Morgan, the largest personal injury law firm in the United States, with 1,000+ attorneys and over $1 billion in annual revenue. He built the ''For the People'' brand into a nationally recognized legal powerhouse. His estimated net worth is $800M+. He is a media personality, entrepreneur, and outspoken public advocate.', 'Reach through Morgan & Morgan''s corporate office or his public social media. Lead with GCU''s pre-law programs and the workforce development pipeline — a talent recruitment and scholarship conversation. His ''For the People'' brand aligns with GCU''s community service mission.', 'Catholic background. Public advocacy for equity and access.', 'GCU''s law-adjacent programs and workforce development story align with Morgan''s ''For the People'' ethos. Scholarship pipeline, intern recruitment, or philanthropy around access to education are the strongest angles.', '["$800M Net Worth", "Morgan & Morgan", "For the People", "Legal Empire", "Philanthropy"]'::jsonb, '[]'::jsonb, NULL, NULL, '[]'::jsonb),
(15, 'SOHK', 'Contact', 'Vic Keller', 'Founder & CEO', 'KLV Capital / Experience Ventures', 'Entrepreneur', 'Dallas, TX', NULL, NULL, 'medium', true, 75, NULL, 'Vic Keller founded and led 14 companies generating over $10 billion in enterprise value. Multiple ventures were acquired by Berkshire Hathaway, making Warren Buffett a direct business partner. He is an EY Entrepreneur of the Year and 5x Inc. 500 Fastest-Growing Companies honoree. He started his career at JPMorgan. He now runs KLV Capital and Experience Ventures, focused on mentoring founders and scaling high-growth companies, and runs the EPIC Community for entrepreneurs.', 'Vic is accessible through his website vickeller.com and EPIC Community. Lead with GCU''s Canyon Ventures and entrepreneurship curriculum — he is explicitly in the business of mentoring founders and would be a natural advisory board member or speaker series guest.', 'Values-driven leader. Faith surfaces in his emphasis on integrity, authentic leadership, and servant leadership. Has worked alongside openly Christian entrepreneurs.', 'Vic''s Berkshire connections and entrepreneurial track record make him a high-credibility advisor for GCU''s Canyon Ventures or business school advisory board. His EPIC Community mirrors the community GCU is building.', '["Berkshire Hathaway Partner", "14 Companies", "$10B Enterprise Value", "EY Entrepreneur", "Mentor"]'::jsonb, '[]'::jsonb, NULL, NULL, '[]'::jsonb),
(16, 'SOHK', 'Contact', 'Joi Hunt', 'Founder & Business Attorney', 'The Hunt Law Group / Firm Credit & Business Group', 'Law', 'Dallas, TX', NULL, NULL, 'medium', true, 70, NULL, 'Joi-Lin Hunt is a serial entrepreneur and business attorney with over 20 years of experience. She earned her JD from Southern University Law Center and her Master''s in Tax Law from SMU. She founded The Hunt Law Group, Quick Money Tax Service, Creme de la Creme Hair, Super Weave Xpress (10 franchise locations), and a multi-million dollar automotive dealership. She has 100K+ TikTok followers teaching entrepreneurs business structure and funding. She rebuilt her entire business empire after leaving an abusive marriage with nothing.', 'Joi is active on social media and accessible. Lead with GCU''s entrepreneurship and business law programs. Her resilience story resonates with GCU''s student population — a speaker series invitation is the natural first ask.', 'Christian. Openly credits her faith and resilience in rebuilding after losing everything. Leads her business content with integrity and purpose-driven principles.', 'Joi''s story of rebuilding from zero and her practical business education work mirrors GCU''s workforce development mission. Strong female entrepreneur voice for GCU''s diverse student community.', '["Business Law", "Serial Entrepreneur", "TikTok Educator", "Women Founders", "Faith"]'::jsonb, '[]'::jsonb, NULL, NULL, '[]'::jsonb),
(17, 'SOHK', 'Contact', 'Clint Phillips', 'Entrepreneur', NULL, 'Entrepreneur', NULL, NULL, NULL, 'medium', true, 60, NULL, 'Christian entrepreneur. Additional background details to be added as intel is gathered for outreach.', 'Establish initial contact and identify the strongest GCU connection point based on their specific background.', 'Christian.', 'Faith alignment with GCU''s mission is the primary connector. Build the relationship first, then identify the specific ask.', '["Christian", "Entrepreneur"]'::jsonb, '[]'::jsonb, NULL, NULL, '[]'::jsonb),
(18, 'SOHK', 'Review', 'Logan Roy', 'Review — May Be Fictional', 'Unknown', 'Other', NULL, NULL, NULL, 'low', false, 0, NULL, 'Logan Roy is a fictional media mogul from HBO''s Succession. If you meant a real person with this name, please edit this card with the correct details. Otherwise, delete this entry.', 'N/A — please review and edit or delete this card.', 'N/A', 'This card needs review.', '["Review Needed"]'::jsonb, '[]'::jsonb, NULL, NULL, '[]'::jsonb),
(19, 'SOHK', 'Whale', 'Tim Tebow', 'Heisman Winner, Author & Philanthropist', 'Tim Tebow Foundation / The Tebow Group', 'Sports', 'Jacksonville, FL', NULL, NULL, 'high', true, 97, NULL, 'Tim Tebow is a Heisman Trophy winner, two-time national champion at Florida, former NFL quarterback, minor league baseball player, sports broadcaster, bestselling author, and founder of the Tim Tebow Foundation. Born to missionary parents in the Philippines, he''s been a defining face of Christian faith in American sports for over 15 years. His foundation brings faith, hope, and love to those in their darkest hour — including special needs ministry, orphan care, anti-human trafficking, and pro-life advocacy. The Tebow Group is his business and media enterprise. He was personally interviewed by James Dumoulin on School of Hard Knocks.', 'Reach through The Tebow Group or Tim Tebow Foundation. GCU''s faith-based campus, sports programs, and Christian identity are a perfect match. He regularly speaks at Christian universities and faith-informed entrepreneurship conferences — GCU is a natural home. James Dumoulin (SOHK) is a direct warm chain.', 'One of the most iconic Christian athletes in American history. Born to missionaries. Openly shares his faith in every public forum. Foundation mission: ''bring Faith, Hope and Love to those needing a brighter day.'' Elected to College Football Hall of Fame 2023. His faith is not a side note — it IS his brand.', 'Tebow has spoken at Olivet Nazarene''s faith-informed entrepreneurship conference — GCU''s equivalent event is the natural next stop. His foundation''s work in special needs, orphan care, and anti-trafficking mirrors CityServe''s community mission exactly. A campus chapel event, commencement, or named scholarship would be a landmark moment for GCU.', '["Heisman Trophy", "Missionary Heritage", "Tim Tebow Foundation", "Anti-Trafficking", "SOHK Network"]'::jsonb, '[{"date": "2023", "title": "Tim Tebow inducted into College Football Hall of Fame", "source": "NCAA"}, {"date": "Apr 2025", "title": "Tim Tebow speaks at Olivet Nazarene on faith, doubt, and entrepreneurship", "source": "Olivet University"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(20, 'SOHK', 'Whale', 'Dave Ramsey', 'Founder & CEO', 'Ramsey Solutions', 'Entrepreneur', 'Nashville, TN', NULL, NULL, 'high', true, 94, NULL, 'Dave Ramsey is America''s most trusted personal finance voice — evangelical Christian, radio host of The Ramsey Show (nationally syndicated), bestselling author of The Total Money Makeover and Financial Peace University, and founder of Ramsey Solutions. Net worth ~$200M. He went bankrupt at 26, rebuilt through Biblical financial principles, and has helped millions of Americans get out of debt. His radio show reaches 18M+ listeners weekly. He was personally interviewed by James Dumoulin on School of Hard Knocks discussing how he found his belief in God.', 'Reach through Ramsey Solutions'' Nashville headquarters or his speaking bureau. GCU''s Financial Literacy and entrepreneurship programs, combined with his personal story of bankruptcy-to-rebuilding, are a perfect alignment. His SOHK interview shows openness to content-driven outreach. Lead with GCU''s affordability model and how it teaches students financial principles he champions.', 'Evangelical Christian who credits his bankruptcy and rebuild entirely to finding God and applying Biblical financial principles. Integrates faith into every aspect of his work. Regularly discusses his belief in God in public interviews. Has described GCU-style affordability as the model for higher education.', 'Dave literally tells his audience to avoid debt and seek affordable education — GCU at $8,900/yr is his dream university. A co-branded Financial Peace University integration with GCU curriculum, or a Ramsey Solutions partnership around student financial literacy, would be a landmark. His audience is exactly GCU''s prospective student and donor base.', '["$200M Net Worth", "Financial Peace", "18M Radio Listeners", "Evangelical Christian", "SOHK Network"]'::jsonb, '[{"date": "2025", "title": "The Ramsey Show continues as top personal finance radio program with 18M+ weekly listeners", "source": "Ramsey Solutions"}, {"date": "2024", "title": "Dave Ramsey interview on School of Hard Knocks \u2014 how he found his belief in God", "source": "School of Hard Knocks"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(21, 'SOHK', 'Review', 'Andy Frisella', 'Co-Founder & CEO', '1st Phorm International', 'Entrepreneur', 'St. Louis, MO', NULL, NULL, 'high', false, 83, NULL, 'Andy Frisella is the co-founder and CEO of 1st Phorm International, a premium nutrition supplement company generating $175M+ in annual revenue. He started with nothing — sleeping on a mattress in the back of his first store — and built a $1B+ portfolio across 1st Phorm, Supplement Superstores, Alpine Sports Products, Carbon Fire Nutrition, and 44Seven Media. He created 75 Hard, a viral mental toughness program with millions of participants. His podcast ''REAL AF'' is one of the top business podcasts in the country. Featured in the most recent School of Hard Knocks podcast episode.', 'Andy is vocal and accessible on social media. Lead with GCU''s entrepreneurship programs and the 75 Hard / discipline culture that resonates with his audience. A campus event, SOAR Bars partnership angle (fitness/supplement overlap), or Canyon Ventures guest session are natural entry points.', 'Values-driven, discipline-focused. Not publicly faith-identified but deeply conservative and community-oriented. Philanthropic work focuses on youth empowerment and education mentorship.', '1st Phorm''s culture of discipline, hard work, and starting from nothing maps perfectly to GCU''s student narrative. His huge social media following (millions across platforms) and the 75 Hard community are GCU''s demographic. A branded partnership or speaker series would have massive reach.', '["$1B Portfolio", "75 Hard", "1st Phorm", "REAL AF Podcast", "SOHK Network"]'::jsonb, '[{"date": "May 2026", "title": "School of Hard Knocks Podcast: Andy Frisella \u2014 He Made $58K in 10 Years, Now His Portfolio Is Worth $1B", "source": "School of Hard Knocks Podcast"}, {"date": "2025", "title": "1st Phorm expands nationwide retail footprint as Supplement Superstores grows", "source": "1st Phorm"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(22, 'SOHK', 'Contact', 'Greg Perlman', 'Founder & CEO', 'GHC Housing Partners / The Change Reaction', 'Real Estate', 'Los Angeles, CA', NULL, NULL, 'high', true, 91, NULL, 'Greg Perlman built GHC Housing Partners into one of America''s largest affordable housing portfolios — 25,000+ units, $2.5B in real estate. He sold half the portfolio for over $1.2B. He and his wife Jodi then pledged to give away 75% of their wealth while alive, founding The Change Reaction — a hyper-local direct giving nonprofit that has disbursed $77M+ to 63,000+ people in need. Named to TIME100 Philanthropy 2026. The Change Reaction partners with social workers, clergy, faith leaders, and community agents to distribute grants within 72 hours. Featured on School of Hard Knocks podcast.', 'Greg is deeply motivated by giving and community impact — he responds to authentic, direct conversations about need. Connect through The Change Reaction or his SOHK appearance. Lead with GCU''s CityServe model and its work in underserved Phoenix communities. A direct giving partnership between The Change Reaction and GCU''s CityServe would be a perfect structural match.', 'Jewish background but explicitly faith-driven in his giving philosophy — partners with clergy, faith leaders, and church networks as ''change agents'' to distribute grants. TIME100 Philanthropy 2026. His foundational belief: ''the wealthy need to become the safety net for hardworking people one missed paycheck from homelessness.''', 'Greg''s $30M/year giving pace and his rapid-response model is exactly what GCU''s CityServe does on the ground. A formal Change Reaction x CityServe partnership, or GCU as a designated ''change agent'' organization, would channel significant philanthropic capital into GCU''s community programs.', '["TIME100 Philanthropy", "$2.5B Real Estate", "75% Giving Pledge", "The Change Reaction", "SOHK Network"]'::jsonb, '[{"date": "May 2026", "title": "TIME100 Philanthropy: Greg and Jodi Perlman \u2014 giving away $30M/year through The Change Reaction", "source": "TIME Magazine"}, {"date": "Oct 2025", "title": "School of Hard Knocks Podcast: Greg Perlman \u2014 Built $2.5B Empire and Chose to Give 75% Away", "source": "School of Hard Knocks Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(23, 'SOHK', 'Review', 'Neil Patel', 'Co-Founder', 'NP Digital / Neil Patel Digital', 'Entrepreneur', 'Las Vegas, NV', NULL, NULL, 'medium', false, 72, NULL, 'Neil Patel became a millionaire at 17, lost it all by 20, then rebuilt to build a 9-figure global digital marketing agency. He co-founded NP Digital, Crazy Egg, Hello Bar, and Kissmetrics. His marketing blog reaches 4M+ monthly visitors. He''s been named a top 100 entrepreneur under 30 by Obama and recognized by Forbes, Wall Street Journal, and UN. Deeply committed to free education — nearly all of his marketing content and courses are free. Featured on School of Hard Knocks podcast.', 'Neil is accessible via his website, LinkedIn, and social media. Lead with GCU''s digital marketing programs and the fact that he built his brand on democratizing education — GCU''s affordability mission resonates. A content partnership, guest lecture, or advisory role around GCU''s marketing programs is natural.', 'Not publicly faith-identified. Deep commitment to free access to education and democratizing entrepreneurship aligns with GCU''s mission.', 'Neil''s entire brand is built on free, accessible entrepreneurship education — GCU''s model is the institutional version of that mission. Guest lecture, advisory board, or co-branded content around digital marketing and entrepreneurship curriculum.', '["9-Figure Marketing Agency", "Free Education Advocate", "4M Monthly Blog Readers", "SOHK Network", "Obama Recognition"]'::jsonb, '[{"date": "2025", "title": "NP Digital named one of the fastest-growing digital marketing agencies globally", "source": "Neil Patel Digital"}, {"date": "2024", "title": "School of Hard Knocks podcast: Neil Patel on building a 9-figure company after losing everything at 20", "source": "School of Hard Knocks Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(24, 'SOHK', 'Review', 'Lucy Guo', 'Co-Founder', 'Scale AI / Backend Capital', 'Technology', 'San Francisco, CA', NULL, NULL, 'medium', false, 74, NULL, 'Lucy Guo is the youngest self-made female billionaire in the world and co-founder of Scale AI, an AI data infrastructure company valued at ~$26B. She dropped out of college via the Thiel Fellowship to help build Scale AI before founding Backend Capital, an early-stage VC firm. She has been featured on Forbes 30 Under 30. Featured on the School of Hard Knocks podcast in May 2026.', 'Reach via LinkedIn or through Scale AI''s public affairs. Lead with GCU''s AI and tech programs and the rare case study of an affordable university producing tech talent. Her Thiel Fellowship background means she questions traditional higher ed — lead with GCU''s practical, outcomes-focused model as a counterpoint.', 'Not publicly faith-identified. Values-driven; speaks openly about family pressure, risk-taking, and purpose in entrepreneurship.', 'GCU''s growing tech and AI programs need industry credibility and advisory relationships. Lucy''s Scale AI connection brings AI infrastructure relevance. Her story as youngest self-made female billionaire is incredibly compelling for GCU''s female student community.', '["Scale AI", "$26B Valuation", "Thiel Fellowship", "Youngest Female Billionaire", "SOHK Network"]'::jsonb, '[{"date": "May 2026", "title": "School of Hard Knocks Podcast: Lucy Guo \u2014 How She Became the World''s Youngest Self-Made Female Billionaire", "source": "School of Hard Knocks Podcast"}, {"date": "2025", "title": "Scale AI secures major government and enterprise AI contracts", "source": "Scale AI"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(25, 'SOHK', 'Review', 'Bill Gurley', 'General Partner', 'Benchmark Capital', 'Technology', 'San Francisco, CA', NULL, NULL, 'medium', false, 68, NULL, 'Bill Gurley is one of the most legendary venture capitalists in Silicon Valley — early investor in Uber, Zillow, OpenTable, Stitch Fix, and dozens of other billion-dollar companies. He''s a General Partner at Benchmark Capital. Known for publicly raising alarms about startup valuations and market excess. Has evaluated thousands of founders and companies over 25+ years. Featured on School of Hard Knocks podcast in March 2026.', 'Bill is a thought leader who engages publicly on Twitter/X and in long-form writing. Lead with GCU''s entrepreneurship and Canyon Ventures — specifically the thesis that the next generation of entrepreneurs is coming from unexpected, non-elite universities. His SOHK appearance shows openness to entrepreneurship education conversations.', 'Not publicly faith-identified. Deeply principled and known for intellectual honesty and ethics in investing.', 'GCU''s Canyon Ventures is exactly the kind of non-traditional entrepreneurship pipeline that disrupts the Stanford/Harvard startup monopoly — that''s a compelling pitch for Bill. Advisory board or guest lecture in Canyon Ventures is the ask.', '["Benchmark Capital", "Early Uber Investor", "Legendary VC", "SOHK Network", "Silicon Valley"]'::jsonb, '[{"date": "Mar 2026", "title": "School of Hard Knocks Podcast: Bill Gurley \u2014 Legendary Investor on Missing Google, Backing Uber", "source": "School of Hard Knocks Podcast"}, {"date": "2025", "title": "Benchmark Capital continues backing next-generation AI and consumer startups", "source": "Benchmark"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(26, 'SOHK', 'Review', 'Eric Spofford', 'Founder & CEO', 'Spofford Enterprises', 'Entrepreneur', 'New Hampshire', NULL, NULL, 'high', true, 88, NULL, 'Eric Spofford overcame heroin addiction and dropped out of high school at 15 before getting sober and building New Hampshire''s first sober living house. He scaled it into a major addiction treatment operation and sold the company for $115 million. He then rebuilt as a private equity investor and entrepreneur. His story of complete rock-bottom to $115M exit is one of the most powerful redemption arcs in American entrepreneurship. Featured on School of Hard Knocks podcast in May 2026.', 'Eric is very open about his story and actively shares it to inspire others. Lead with GCU''s CityServe work around addiction recovery, community transformation, and second-chance programs. His story is a perfect GCU chapel or commencement speaker. Connect through his social media or his speaking engagements.', 'Deeply faith-driven. His recovery and entire business philosophy are rooted in the belief that redemption is possible for anyone. Actively speaks about God and faith in recovery contexts. His story mirrors the transformation narrative at the core of GCU''s mission.', 'Eric''s story — rock bottom, recovery, $115M exit — is the GCU miracle narrative. CityServe''s addiction recovery work and second-chance community programs are a direct institutional match. Chapel speaker, CityServe partner, or scholarship in his name for students in recovery.', '["$115M Exit", "Addiction Recovery", "Redemption Story", "Second Chances", "SOHK Network"]'::jsonb, '[{"date": "May 2026", "title": "School of Hard Knocks Podcast: Eric Spofford \u2014 He Was Addicted to Drugs, Now He''s Sold a $115 Million Company", "source": "School of Hard Knocks Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(27, 'SOHK', 'Review', 'Greg LaVecchia', 'Co-Founder', 'Bloom Nutrition', 'Entrepreneur', 'Austin, TX', NULL, NULL, 'high', false, 82, NULL, 'Co-founded Bloom Nutrition with his wife and bootstrapped to $180M revenue with no investors — now 70,000 retail doors and $23M weekly net sales. Had a 2.5 GPA in college. Bet $1M on Target distribution and won. Featured on SOHK podcast May 2026.', 'Lead with GCU''s ''unlikely founder'' message — his 2.5 GPA origin is exactly GCU''s point that traditional metrics don''t define success. Canyon Ventures speaker.', 'Family-first values. Married co-founder story.', '$1B supplement brand from 2.5 GPA. Canyon Ventures speaker or CPG/business curriculum advisory.', '["$1B Supplement Brand", "Bootstrap", "SOHK Network", "Consumer Goods", "Bloom Nutrition"]'::jsonb, '[{"date": "May 2026", "title": "SOHK: Greg LaVecchia \u2014 He Had a 2.5 GPA, Now He''s Got a $1 Billion Brand", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(28, 'SOHK', 'Review', 'Patrick Terry', 'Co-Founder', 'P. Terry''s Burger Stand', 'Entrepreneur', 'Austin, TX', NULL, NULL, 'high', true, 87, NULL, 'Started P. Terry''s at 47 with a 527-sq-ft Austin burger stand competing directly against McDonald''s. Grew to 38 locations and 1,800 employees. Refused franchise deals and private equity to preserve culture. Featured on SOHK May 2026.', 'Lead with GCU''s ''it''s never too late'' narrative — perfect for non-traditional students. His values-culture story mirrors GCU''s mission-first identity.', 'Christian. Faith-informed leadership throughout the company''s culture.', '''Started at 47'' story is perfect for non-traditional students — a growing GCU population. Workforce development, speaker series, values-driven business curriculum.', '["Late Starter", "Faith Leader", "Austin TX", "Values Culture", "SOHK Network"]'::jsonb, '[{"date": "May 2026", "title": "SOHK: Patrick Terry \u2014 Started at 47 and Beat McDonald''s", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(29, 'SOHK', 'Review', 'Alison & Stephen Ellsworth', 'Co-Founders', 'Poppi', 'Entrepreneur', 'Austin, TX', NULL, NULL, 'medium', true, 76, NULL, 'Founded Poppi from personal health struggles, went viral on Shark Tank, built to $500M/year and sold to PepsiCo for $2 billion in 4 years. Built by married co-founders through social media and influencer marketing. Featured on SOHK April 2026.', 'Connect through Texas/Austin community. Lead with Canyon Ventures and the husband-wife founder story.', 'Stephen has spoken about faith guiding their business decisions.', '$2B exit in 4 years from a kitchen idea. Perfect Canyon Ventures inspiration story.', '["$2B Exit", "Poppi", "Shark Tank", "Husband-Wife Founders", "SOHK Network"]'::jsonb, '[{"date": "Apr 2026", "title": "SOHK: Poppi Founders \u2014 $500M/Year Soda Sold for $2 Billion", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(30, 'SOHK', 'Review', 'Daniel Lubetzky', 'Founder', 'KIND Snacks', 'Entrepreneur', 'New York, NY', NULL, NULL, 'high', true, 89, NULL, 'Founded KIND Snacks from a $24,000 salary after Stanford Law, built to a $5B company sold to Mars. His father survived the Holocaust — Daniel''s ''AND thinking'' (profitable AND socially responsible) defines his brand. Featured on SOHK January 2026.', 'Lead with GCU''s social impact mission and ''AND'' philosophy. His foundation ReStart supports coexistence work.', 'Jewish. Deeply values-driven, social conscience-first entrepreneurship.', '$5B exit from purpose-driven capitalism. Guest lecture or Canyon Ventures featured speaker.', '["$5B Exit", "KIND Snacks", "Purpose-Driven Capitalism", "Holocaust Survivor Son", "SOHK Network"]'::jsonb, '[{"date": "Jan 2026", "title": "SOHK: Daniel Lubetzky \u2014 From $24K Salary to $5 Billion Company", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(31, 'SOHK', 'Contact', 'Kirt Linington', 'Founder', 'Service Scalers', 'Entrepreneur', 'Texas', NULL, NULL, 'medium', true, 78, NULL, 'South Africa-born, came to America with $700, started door-knocking at 42 while working corporate job, built $62M in roofing revenue, sold for a nine-figure exit in 2022. Featured on SOHK January 2026.', 'Lead with GCU''s construction and trades programs. Immigration-to-success story resonates with diverse student body.', 'Faith-driven discipline and integrity in leadership.', 'Nine-figure exit from trades/home services — directly relevant to GCU''s CM program.', '["Nine-Figure Exit", "South Africa", "Immigration Story", "Trades", "SOHK Network"]'::jsonb, '[{"date": "Jan 2026", "title": "SOHK: Kirt Linington \u2014 Came to America with $700, Sold for 9 Figures", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(32, 'SOHK', 'Review', 'Jim Keyes', 'Former CEO', '7-Eleven & Blockbuster', 'Entrepreneur', 'Dallas, TX', NULL, NULL, 'high', false, 80, NULL, 'Grew up dirt poor, became CEO of 7-Eleven (2000-2005) and Blockbuster (2007-2011). Navigated 7-Eleven''s near-bankruptcy and Blockbuster''s collapse. Publicly states ''education is the key to success.'' Active education philanthropist. Featured on SOHK twice (2023 and 2026).', 'Lead with GCU''s affordability model and education-as-equalizer. His Fortune 500 background makes him a compelling advisory board candidate.', 'Deep belief in education, service, and community responsibility.', '''Education is the key to success'' is his statement — GCU is his answer. Advisory board or endowed lecture.', '["Fortune 500 CEO", "7-Eleven", "Education Advocate", "SOHK Network", "Two Episodes"]'::jsonb, '[{"date": "Feb 2026", "title": "SOHK: Jim Keyes \u2014 What Always Happens Before a Company Crash", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(33, 'SOHK', 'Review', 'John Caudwell', 'Founder', 'Phones 4u', 'Entrepreneur', 'London, UK', NULL, NULL, 'medium', false, 68, NULL, 'Built Phones 4u from scratch to £1.5B exit, 10,000 employees. Lost 95% of supply and rebuilt. Has donated over £100M to charity. Featured on SOHK March 2026.', 'International prospect. Lead with GCU''s international programs and philanthropy alignment.', 'Values-driven philanthropist.', 'Philanthropy record relevant to GCU development. Named scholarship or international program.', '["\u00a31.5B Exit", "Phones 4u", "UK Billionaire", "\u00a3100M Philanthropy", "SOHK Network"]'::jsonb, '[{"date": "Mar 2026", "title": "SOHK: John Caudwell \u2014 British Billionaire Who Built $2B Empire", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(34, 'SOHK', 'Review', 'Forbes Riley', 'Speaker & Entrepreneur', 'SpinGym / Forbes Factor', 'Entrepreneur', 'Los Angeles, CA', NULL, NULL, 'medium', false, 70, NULL, 'The ''Pitch Queen'' — sold $2.5B+ in products through TV, infomercials, and live demos. 64,000 units in 24 hours. Master sales trainer and speaker. Featured on SOHK February 2026.', 'Lead with GCU''s entrepreneurship and business communication programs. Her pitch training is exactly what Canyon Ventures students need.', 'Resilience and purpose-driven.', '$2.5B in sales expertise — guest lecture or sales training workshop for Canyon Ventures.', '["$2.5B in Sales", "Pitch Queen", "TV Personality", "Sales Trainer", "SOHK Network"]'::jsonb, '[{"date": "Feb 2026", "title": "SOHK: Forbes Riley \u2014 From Actress to Pitch Queen, $2.5B in Sales", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(35, 'SOHK', 'Review', 'Ari Rastegar', 'Founder & CEO', 'Rastegar Property Company', 'Real Estate', 'Austin, TX', NULL, NULL, 'high', true, 85, NULL, 'Started with $3,000 from flipping burgers and built a multi-billion dollar real estate portfolio reshaping major US cities. Wrote himself a $1 billion check at 23 and carried it 15 years. Featured on SOHK January 2026.', 'Accessible on social. Lead with GCU''s campus development and Phoenix real estate story. Urban development focus aligns with GCU expansion.', 'Openly Christian. Faith, vision, and waiting on God''s timing are central to his business philosophy.', 'Austin real estate developer with Christian faith — advisory board, real estate curriculum, or campus planning relationship.', '["$1B+ Real Estate", "Christian", "Urban Development", "Austin TX", "SOHK Network"]'::jsonb, '[{"date": "Jan 2026", "title": "SOHK: Ari Rastegar \u2014 $3,000 Deal That Built a Billion-Dollar Real Estate Empire", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
