(80, 'SOHK', 'Review', 'Richard Harpin', 'Founder & CEO', 'HomeServe', 'Entrepreneur', 'London, UK', NULL, NULL, 'medium', false, 70, NULL, 'Built HomeServe from £50K to £4.1B global company in 10 countries. Was $10K from bankruptcy before the pivot. Has a 9-step framework for building a billion-pound company. Featured on SOHK April 2026.', 'Lead with GCU''s international programs and home services/construction program alignment.', 'Resilience and practical framework-driven.', 'HomeServe''s home services model relevant to GCU''s construction and trades programs. Guest lecture.', '["\u00a34.1B Company", "HomeServe", "9-Step Framework", "UK Entrepreneur", "SOHK Network"]'::jsonb, '[{"date": "Apr 2026", "title": "SOHK: Richard Harpin \u2014 $10K From Bankruptcy to $4B Company", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(81, 'SOHK', 'Review', 'Jack Dumoulin', 'Co-Founder', 'School of Hard Knocks', 'Media', 'Austin, TX', 'jack@shophardknocks.com', NULL, 'high', true, 85, NULL, 'Co-founder of SOHK alongside brothers James and Joshua Smith. Runs School of Mentors — $99/month community with 6,200+ entrepreneurs getting weekly live calls with billionaires. Featured on Fox & Friends.', 'Jack runs the operational side of SOHK. Lead with Canyon Ventures and a GCU x SOHK partnership that makes GCU the featured institution in SOHK content.', 'Christian. SOHK featured on Faith Driven Entrepreneur. Values-aligned.', 'Jack runs School of Mentors — a GCU x SOHK partnership could make GCU the featured affordable university for SOHK''s million+ audience.', '["SOHK Co-Founder", "School of Mentors", "6200+ Members", "Fox & Friends", "Entrepreneur"]'::jsonb, '[{"date": "Oct 2025", "title": "Fox News: School of Hard Knocks turns billionaire interviews into multimillion dollar empire", "source": "Fox News"}]'::jsonb, NULL, NULL, '[]'::jsonb),
(82, 'SOHK', 'Review', 'Joshua Smith', 'Co-Founder', 'School of Hard Knocks', 'Media', 'Austin, TX', 'joshua@shophardknocks.com', NULL, 'high', true, 83, NULL, 'Third co-founder of SOHK alongside James and Jack Dumoulin. Critical to SOHK''s operational and content infrastructure generating $1M+/month. Featured on Fox & Friends.', 'Accessible through SOHK social channels. Lead with Canyon Ventures and GCU x SOHK partnership.', 'Christian. SOHK featured on Faith Driven Entrepreneur.', 'Three SOHK co-founders on this list = significant relationship opportunity. Formal GCU x SOHK media partner would be transformational.', '["SOHK Co-Founder", "Fox & Friends", "Media Empire", "Content Creator", "Faith Network"]'::jsonb, '[{"date": "Oct 2025", "title": "Fox News: SOHK Co-founders on Fox & Friends", "source": "Fox News"}]'::jsonb, NULL, NULL, '[]'::jsonb),
