(84, 'SOHK', 'Review', 'Andy Stanley', 'Senior Pastor', 'North Point Ministries', 'Entrepreneur', 'Atlanta, GA', NULL, NULL, 'high', true, 91, NULL, 'Founding pastor of North Point Ministries serving 100K+ people weekly. One of the most respected evangelical communicators in America. Author of 30+ books. Son of Charles Stanley.', 'Andy speaks at Christian leadership events and universities. Lead with GCU''s academic and chapel programs.', 'Among the most respected evangelical voices in America.', 'Andy Stanley''s endorsement of GCU''s curriculum would be nationally significant. Chapel speaker or advisory role.', '["North Point Ministries", "100K Weekly", "30+ Books", "Evangelical Leader", "Charles Stanley Son"]'::jsonb, '[]'::jsonb, NULL, NULL, '[]'::jsonb),
(86, 'SOHK', NULL, 'RJ Jain', 'Founder & CEO', 'Price.com', 'Technology', 'Michigan', NULL, NULL, 'medium', false, 66, NULL, 'Sold a startup to Google for nine figures, now building Price.com — AI shopping platform at ~$200M valuation. Grew up in India, studied in Michigan. Featured on SOHK April 2026.', 'Lead with GCU''s AI and tech programs and the immigrant entrepreneur story.', 'Resilience and purpose-driven.', 'Google exit + $200M AI company = compelling case study for GCU''s tech programs.', '["Google Exit", "AI Company", "$200M", "Immigrant Founder", "SOHK Network"]'::jsonb, '[{"date": "Apr 2026", "title": "SOHK: RJ Jain \u2014 Sold to Google, Now Building $200M Company", "source": "SOHK Podcast"}]'::jsonb, NULL, NULL, '[]'::jsonb);

