(1199, 'KIC', NULL, 'Keith Townsend', 'FCA Leader', 'Friends University Athletics; Fellowship of Christian Athletes', 'Sports', NULL, NULL, NULL, 'low', true, 44, NULL, 'Dedicating his life to spiritual growth of 700+ student-athletes and coaches via FCA, the largest interdenominational Christian sports organization. States: "I work so hard to help the student-athletes and coaches... grow spiritually in their faith in Christ... there are only two things that last for eternity: God''s word and people''s souls." Active sports ministry leader with direct discipleship impact on 700+ athletes and coaches across collegiate athletics.', 'Active sports ministry leader with direct discipleship impact on 700+ athletes and coaches across collegiate athletics.', 'States: "I work so hard to help the student-athletes and coaches... grow spiritually in their faith in Christ... there are only two things that last for eternity: God''s word and people''s souls."', NULL, '[]'::jsonb, '[]'::jsonb, 'Dedicating his life to spiritual growth of 700+ student-athletes and coaches via FCA, the largest interdenominational Christian sports organization.', NULL, '["https://friendsathletics.com/staff-directory/keith-townsend/252", "http://stories.friendsathletics.com/2025/01/21/keithtownsend/", "https://friendsathletics.com/news/2025/7/30/frnd-friends-fca-program-welcomes-largest-intern-class-for-2025-26.aspx", "https://www.ksfca.org/keith-townsend"]'::jsonb),
(1200, 'KIC', NULL, 'Sarah Huckabee Sanders', 'Governor of Arkansas', 'State of Arkansas', 'Recent Christian Governors (US States)', NULL, NULL, NULL, 'low', true, 44, NULL, 'Sarah Huckabee Sanders served as White House Press Secretary under President Trump from 2017 to 2019 and was elected Governor of Arkansas in 2022, becoming the state''s first female governor. She is a Southern Baptist Christian who has spoken openly about how her faith shapes her governance, including signing legislation to allow the Ten Commandments to be displayed in Arkansas public schools. Sanders is the daughter of former Arkansas Governor and ordained minister Mike Huckabee, and her Christian faith is deeply woven into her public identity and political philosophy. As a high-profile female governor with a strong evangelical public witness and national name recognition, she represents a compelling profile for GCU''s Kingdom Impact Council.', 'High-profile household-name current governor with publicly stated born-again faith and evangelical family legacy.', 'Devout evangelical raised by pastor Mike Huckabee; has shared faith journey publicly.', NULL, '[]'::jsonb, '[]'::jsonb, 'First woman governor of Arkansas with national White House profile and explicit born-again Christian testimony.', NULL, '["https://governor.arkansas.gov/newsroom/", "https://en.wikipedia.org/wiki/Sarah_Huckabee_Sanders", "https://www.focusonthefamily.com/faith/sarah-huckabee-sanders-testimony/", "https://www.ncronline.org/news/all-president-s-clergymen"]'::jsonb),
(1201, 'KIC', NULL, 'Kayleigh McEnany', NULL, NULL, 'Recent Christian White House Senior Staff (Household)', 'Tampa, Florida', NULL, NULL, 'low', true, 44, NULL, 'Kayleigh McEnany served as White House Press Secretary under President Trump from 2020 to 2021, and prior to that as national press secretary for the 2020 campaign. She is a Harvard Law graduate and a devout Catholic who has spoken publicly about her faith sustaining her through a preventive double mastectomy she underwent after testing positive for the BRCA gene mutation. McEnany is a Fox News host and author, and her willingness to discuss her faith, her health journey, and her pro-life convictions in public forums has made her a recognized voice at the intersection of conservative politics and Christian witness. Her academic credentials, media presence, and personal faith testimony make her a distinctive figure in the Christian public sphere.', 'High-profile press secretary with published evangelical testimony and pro-life advocacy.', 'Evangelical Christian who released book ''For Such a Time as This'' detailing faith journey and pro-life conversion.', NULL, '[]'::jsonb, '[]'::jsonb, 'White House Press Secretary during impeachments and COVID-19 with documented evangelical conversion.', NULL, '["https://www.foxnews.com/person/m/kayleigh-mcenany", "https://www.ncronline.org/news/all-president-s-clergymen", "https://en.wikipedia.org/wiki/Kayleigh_McEnany", "https://fedsoc.org/bio/kayleigh-mcenany"]'::jsonb),
(1202, 'KIC', NULL, 'Mick Mulvaney', NULL, NULL, 'Recent Christian White House Senior Staff (Household)', 'Indian Land, South Carolina', NULL, NULL, 'low', true, 44, NULL, 'Mick Mulvaney served as Director of the Office of Management and Budget, Acting White House Chief of Staff, and Special Envoy to Northern Ireland under President Trump. A South Carolina Republican, Mulvaney is a Roman Catholic who has spoken about his faith informing his fiscal conservatism and policy approach. He is a graduate of Georgetown University and has remained active in conservative political circles following his White House tenure. His Catholic faith, senior executive government experience, and deep connections to Republican fiscal policy make him a relevant figure for GCU''s Kingdom Impact Council in the arena of faith and public service.', 'Chief-of-staff-rank Catholic with regular Mass attendance and public faith integration.', 'Catholic who attends Mass regularly and has discussed faith''s role in conservative principles.', NULL, '[]'::jsonb, '[]'::jsonb, 'Acting Chief of Staff and OMB Director who led budget reforms during Trump administration.', NULL, '["https://archdpdx.org/mulvaney-confirmed-as-omb-director/", "https://religionnews.com/2024/12/16/trumps-cabinet-selections-represent-an-unusual-slice-of-american-religious-life/", "https://www.thestate.com/news/politics-government/article_mick-mulvaney.html", "https://www.ncregister.com/news/trump-omb-pick-mick-mulvaney-a-socially-conservative-catholic"]'::jsonb),
(1203, 'KIC', NULL, 'Marc Lotter', NULL, 'America First Policy Institute', 'Christian Congressional Leadership Staff (Household)', NULL, NULL, NULL, 'low', true, 44, NULL, 'Handled high-profile White House communications during the Trump administration as Communications Director for Vice President Mike Pence. Active in evangelical circles, with public testimony on his Christian faith and role in faith advisory groups during the Pence era. Senior White House communications strategist with demonstrated evangelical commitment and experience shaping faith-based messaging at executive level.', 'Senior White House communications strategist with demonstrated evangelical commitment and experience shaping faith-based messaging at executive level.', 'Active in evangelical circles, with public testimony on his Christian faith and role in faith advisory groups during the Pence era.', NULL, '[]'::jsonb, '[]'::jsonb, 'Handled high-profile White House communications during the Trump administration as Communications Director for Vice President Mike Pence.', NULL, '["https://americafirstpolicy.com/issues/afpi-adds-marc-lotter", "https://www.americafirstpolicy.com/team/marc-lotter", "https://www.sourcewatch.org/index.php/America_First_Policy_Institute"]'::jsonb),
