(1934, 'KIC', NULL, 'Cardinal Joseph Tobin', 'Archbishop of Newark', 'Roman Catholic Church, Archdiocese of Newark', 'US Catholic Bishops & Cardinals', NULL, NULL, NULL, 'low', true, 37, NULL, 'Leading a major U.S. archdiocese and active participant in the 2025 papal conclave. Redemptorist priest and cardinal elevated in 2016 who has shared public testimony on mercy and evangelization in Catholic media interviews. Active cardinal leading major archdiocese with public witness and Vatican participation.', 'Active cardinal leading major archdiocese with public witness and Vatican participation.', 'Redemptorist priest and cardinal elevated in 2016 who has shared public testimony on mercy and evangelization in Catholic media interviews.', NULL, '[]'::jsonb, '[]'::jsonb, 'Leading a major U.S. archdiocese and active participant in the 2025 papal conclave.', NULL, '["https://www.osvnews.com/here-are-11-cardinals-with-american-ties-who-will-cast-votes-for-the-next-pope/", "https://press.vatican.va/content/salastampa/en/documentation/cardinali_biografie/cardinali_bio_tobin_j.html", "https://rcan.org/cardinal-tobin/", "https://rcan.org/cardinal-joseph-w-tobin-to-ordain-new-auxiliary-bishop/"]'::jsonb),
(1935, 'KIC', NULL, 'Kelcy Warren', 'Executive Chairman', 'Energy Transfer', 'Christian Energy & Utility Executives (Household)', NULL, NULL, NULL, 'low', true, 34, NULL, 'Kelcy Warren is executive chairman of Energy Transfer, one of the largest midstream energy companies in the United States, operating approximately 125,000 miles of pipeline infrastructure that moves natural gas, crude oil, and refined products across 44 states. Warren co-founded Energy Transfer in 1996 as a small intrastate natural gas pipeline company in Texas and built it through decades of aggressive acquisitions into one of America''s most significant energy infrastructure enterprises. He is known within Texas energy and Christian communities for his public Christian testimony and faith community involvement. Warren is a prominent donor to conservative and faith-aligned causes in Texas, and his outsized influence on America''s energy infrastructure — combined with his documented Christian faith — makes him a significant figure for GCU''s Kingdom Impact Council.', 'Household-name pipeline magnate with documented public Christian faith testimony and community involvement.', 'Public Christian testimony and involvement in faith communities in Texas energy scene.', NULL, '[]'::jsonb, '[]'::jsonb, 'Built Energy Transfer into a pipeline giant with massive infrastructure including the Dakota Access pipeline.', NULL, '["https://chiefexecutive.net/under-ceo-and-co-founder-kelcy-l-warren-energy-transfer-goes-international/", "https://kelcy-warren.webflow.io", "https://texasbusiness.org/wp-content/uploads/2021/03/Kelcy-Warren-Bio.pdf", "https://en.wikipedia.org/wiki/Kelcy_Warren"]'::jsonb),
(1936, 'KIC', NULL, 'Mike Hopkins', 'NASA Astronaut', 'NASA', 'christian_astronauts_aerospace', NULL, NULL, NULL, 'low', true, 34, NULL, 'Mike Hopkins is a NASA astronaut and U.S. Air Force colonel who commanded SpaceX Crew-1 — the first operational commercial crew mission to the International Space Station — in 2020 and 2021, logging over 166 days in space as part of Expedition 64. The Crew-1 mission marked a milestone in the commercial spaceflight era, demonstrating NASA''s partnership with SpaceX for routine crew transportation to the ISS. Hopkins is publicly identified with Christian faith and his military career includes service as a flight test engineer and combat pilot. His operational command of the landmark Crew-1 mission, combined with his military background and Christian faith, align well with GCU''s values of service, leadership, and purposeful calling.', 'Current active astronaut with public Christian faith commitment.', 'Publicly identified with Christian faith, aligning with Christian leadership context.', NULL, '[]'::jsonb, '[]'::jsonb, 'Commanded SpaceX Crew-1 to the ISS in 2020 and Expedition 64, advancing commercial crew program.', NULL, '["https://www.churchpop.com/the-story-of-the-astronaut-who-took-the-eucharist-to-space/", "https://www.catholicsun.org/2024/07/23/space-force-colonel-mike-hopkins-recounts-venturing-into-the-void-with-the-eucharist/", "https://www.youtube.com/watch?v=tZ1EmAdrhg0", "https://www.youtube.com/watch?v=PicN2vBOn6w"]'::jsonb),
(1937, 'KIC', NULL, 'Archbishop Foley Beach', 'Archbishop of the Anglican Church in North America', NULL, 'Eastern Orthodox, Anglican & Methodist US Leaders', NULL, NULL, NULL, 'low', true, 34, NULL, 'Current leader of the Anglican Church in North America with global Anglican influence through GAFCON. ACNA primate; publicly affirms the authority of Scripture and Anglican worship tradition. Major Anglican primate directing largest traditional Anglican denomination in North America.', 'Major Anglican primate directing largest traditional Anglican denomination in North America.', 'ACNA primate; publicly affirms the authority of Scripture and Anglican worship tradition.', NULL, '[]'::jsonb, '[]'::jsonb, 'Current leader of the Anglican Church in North America with global Anglican influence through GAFCON.', NULL, '["https://anglicanchurch.net/archbishop-beach/", "https://livingchurch.org/news/bp-foley-beach-lead-acna/", "https://churchrez.org/foley-beach-invested-as-archbishop-of-the-acna/", "https://en.wikipedia.org/wiki/Foley_Beach"]'::jsonb),
(1938, 'KIC', NULL, 'Adam Hamilton', 'Senior pastor of Church of the Resurrection', NULL, 'Eastern Orthodox, Anglican & Methodist US Leaders', NULL, NULL, NULL, 'low', true, 34, NULL, 'Built one of the largest United Methodist megachurches and authored bestselling faith books. United Methodist pastor whose sermons and bestselling books publicly expound Wesleyan theology and Scripture. Major Methodist megachurch leader and prolific Christian author with national influence.', 'Major Methodist megachurch leader and prolific Christian author with national influence.', 'United Methodist pastor whose sermons and bestselling books publicly expound Wesleyan theology and Scripture.', NULL, '[]'::jsonb, '[]'::jsonb, 'Built one of the largest United Methodist megachurches and authored bestselling faith books.', NULL, '["https://resurrection.church/enote/weekly-update-from-pastor-adam-april-24-2026/", "https://en.wikipedia.org/wiki/Adam_Hamilton_(pastor)", "https://www.aspenideas.org/speakers/adam-hamilton", "https://resurrection.church/staff/"]'::jsonb),
(1939, 'KIC', NULL, 'Jeff Hildebrand', 'Co-Founder and President', 'Hilcorp Energy', 'Christian Energy & Utility Executives (Household)', NULL, NULL, NULL, 'low', true, 24, NULL, 'Jeff Hildebrand is co-founder and president of Hilcorp Energy Company, which has become America''s largest privately held oil and gas producer through a distinctive employee ownership model and aggressive acquisition strategy. Hildebrand is known for his innovative approach to company culture, most famously demonstrated when he gave every Hilcorp employee a $100,000 bonus in 2014 when the company hit a production milestone — a gesture that generated national attention and reflected his belief in sharing the fruits of the business with those who built it. He grew Hilcorp from a small startup to a company producing over 200,000 barrels of oil equivalent per day, all while keeping it private and employee-owned. Hildebrand is known within Houston''s energy and Christian communities for his faith commitment, and his combination of unconventional leadership philosophy, private-company scale, and Christian faith make him a compelling and distinctive profile.', 'Billionaire energy entrepreneur with documented Christian faith commitment and major industry influence.', 'Known for Christian faith signals via company culture and personal testimony in energy circles.', NULL, '[]'::jsonb, '[]'::jsonb, 'Grew Hilcorp into America''s largest privately held oil producer through aggressive acquisitions and operations.', NULL, '["https://texasbusiness.org/hall-of-fame-old/jeffery-d-hildebrand/", "https://www.pge.utexas.edu/alumnus/jeffery-d-hildebrand-bs-geology-81-mspe-85/", "https://www.hinchilla.com/funders-us/760699250-hildebrand-foundation"]'::jsonb),
